                            case .userFallback:
                                print("User chose to enter password.")
                                // You might want to present a password fallback UI here
                            case .biometryNotAvailable:
                                print("Biometry not available on this device.")
                            case .biometryNotEnrolled:
                                print("Biometry not enrolled.")
                            case .biometryLockout:
                                print("Biometry is locked out. Too many failed attempts.")
                            case .appCancel:
                                print("Authentication cancelled by app.")
                            case .invalidContext:
                                print("Invalid LAContext.")
                            default:
                                print("Biometric authentication failed: \(laError.localizedDescription)")
                            }
                        } else {
                            print("Authentication failed with unknown error: \(authenticationError?.localizedDescription ?? "Unknown error")")
                        }
                        completion(false)
                    }
                }
            }
        } else {
